INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_ac1d0f33172cc90cd1',NULL,'officer','/''ɒfisә/','n. 军官, 主管, 官员, 公务员\nvt. 指挥；英英释义：n. a person authorized to serve in a position of authority on a vessel\nv. direct or command as an officer；词形变化：s:officers/i:officering/p:officered/3:officers/d:officered','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
