INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_9839f9d3c09db56d11',NULL,'organ','/''ɒ:gәn/','n. 风琴, 器官, 元件, 机构, 机关\n[电] 风琴；英英释义：n. a fully differentiated structural and functional unit in an animal that is specialized for some particular function\nn. a government agency or instrument devoted to the performance of some specific function\nn. a periodical that is published by a special interest group\nn. wind instrument whose sound is produced by means of pipes arranged in sets supplied with air from a bellows and controlled from a large complex musical keyboard；词形变化：s:organs','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_fa8bbab5d180a7243d',NULL,'organic','/ɒ:''gænik/','a. 器官的, 有机的, 组织的, 根本的\n[医] 器官的, 有生命的, 有机的, 器质的；英英释义：n. a fertilizer that is derived from animal or vegetable matter\na. relating or belonging to the class of chemical compounds having a carbon basis\na. being or relating to or derived from or having properties characteristic of living organisms\na. involving or affecting physiology or bodily organs；词形变化：s:organics','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_c9ac4e229f23acc4ed',NULL,'organism','/''ɒ:gәnizm/','n. 生物, 有机体, 社会组织\n[医] 生物[体],[有]机体；英英释义：n. a living thing that has (or can develop) the ability to act or function independently\nn. a system considered analogous in structure or function to a living body；词形变化：s:organisms','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_65ad70f89aed202df8',NULL,'organization','/.ɒ:gәnai''zeiʃәn/','n. 组织, 结构, 团体, 体制\n[医] 组织, 机构, 机化(血栓或坏死组织)；英英释义：n. a group of people who work together\nn. the act of organizing a business or an activity related to a business\nn. an ordered manner; orderliness by virtue of being methodical and well organized\nn. the activity or result of distributing or disposing persons or things properly or methodically；词形变化：s:organizations','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_c8b29361766a683cb3',NULL,'organize','/''ɒ:gәnaiz/','vt. 组织, 有机化, 给予生机\nvi. 组织起来；英英释义：v. cause to be structured or ordered or operating according to some principle or idea\nv. bring order and organization to\nv. arrange by systematic planning and united effort；词形变化：d:organized/i:organizing/p:organized/3:organizes','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
