INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_f351edae894f3a5ee0',NULL,'oriental','/.ɒ:ri''entl/','n. 东方人, 亚洲人\na. 东方诸国的, 亚洲的, 东方的；英英释义：n. a member of an Oriental race; the term is regarded as offensive by Asians (especially by Asian Americans)\ns. denoting or characteristic of countries of Asia；词形变化：s:orientals','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
