INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_ad8204142e814a9967',NULL,'origin','/''ɒridʒin/','n. 起源, 起因, 出身, 开端\n[计] 原点; 起始地址; 信件来源的相关数据；英英释义：n. properties attributable to your ancestry\nn. an event that is a beginning; a first part or stage of subsequent events\nn. the point of intersection of coordinate axes; where the values of the coordinates are all zero\nn. the source of something''s existence or from which it derives or is derived；词形变化：s:origins','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
