INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_653486295be7da56c7',NULL,'overhead','/''әuvәhed/','n. 经常开支, 普通用费, 天花板\na. 在头上的, 高架的\nadv. 在头顶上, 在空中, 在高处, 从头到脚全部没入地\n[计] 总开销; 额外开销；英英释义：n. (nautical) the top surface of an enclosed space on a ship\nn. a hard return hitting the tennis ball above your head\na. located or originating from above\nr. above your head; in the sky；词形变化：s:overheads','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_681152e7ca6ec6f3c7',NULL,'overhear','/.әuvә''hiә/','vt. 无意中听到, 偷听；英英释义：v hear, usually without the knowledge of the speakers；词形变化：d:overheard/p:overheard/i:overhearing/3:overhears','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
