INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_cd949890acd269a1c6',NULL,'overlook','/.әuvә''luk/','vt. 俯瞰, 远眺, 没注意到\nn. 眺望, 俯瞰到的景色；英英释义：n. a high place affording a good view\nv. look past, fail to notice\nv. watch over；词形变化：i:overlooking/d:overlooked/3:overlooks/p:overlooked','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
