INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_13fda90509bd20604f',NULL,'overturn','/.әuvә''tә:n/','n. 倾覆, 破灭, 革命\nvt. 推翻, 颠倒\nvi. 翻倒；英英释义：n. an improbable and unexpected victory\nv. turn from an upright or normal position\nv. cause to overturn from an upright or normal position；词形变化：d:overturned/p:overturned/i:overturning/3:overturns','','考研核心·学术','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
