INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_93da04e13cbe2fef50',NULL,'overwhelming','/.әuvә''hwelmiŋ/','a. 压倒性的, 无法抵抗的；英英释义：v overcome, as with emotions or perceptual stimuli\nv charge someone with too many tasks\nv cover completely or make imperceptible\nv overcome by superior force\ns so strong as to be irresistible\ns very intense；词形变化：1:i/0:overwhelm','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
