INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_fe4a2c2dbf8b4b3a50',NULL,'pan','/pæn/','n. 平锅, 浅盘, 盆地, 硬土层, 拍摄全景\nv. 上下左右移动, 摇镜头, 淘洗, 淘金；英英释义：n. cooking utensil consisting of a wide metal vessel\nn. (Greek mythology) god of fields and woods and shepherds and flocks; represented as a man with goat''s legs and horns and ears; identified with Roman Sylvanus or Faunus\nn. shallow container made of metal\nn. chimpanzees; more closely related to Australopithecus than to other pongids；词形变化：s:pans/d:panned/i:panning/p:panned/3:pans','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
