INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_ce174646d898d1fbee',NULL,'panel','/''pænl/','n. 嵌板, 仪表板, 专题讨论小组, 全体陪审员\nvt. 嵌镶板；英英释义：n. sheet that forms a distinct (usually flat and rectangular) section or component of something\nn. (law) a group of people summoned for jury service (from whom a jury will be chosen)\nn. a group of people gathered for a special purpose as to plan or discuss an issue or judge a contest etc\nn. a soft pad placed under a saddle；词形变化：s:panels/d:panelled/i:panelling/p:panelled/3:panels','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
