INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_5cbaac22f116268f26',NULL,'parallel','/''pærәlel/','n. 平行, 对比, 相匹敌之物\na. 平行的, 相似的\nvt. 与...平行, 与...相似, 相比, 使平行\n[计] 并联; 并行；英英释义：n. (mathematics) one of a set of parallel geometric figures (parallel lines or planes)\nv. be parallel to\nv. make or place parallel to something\na. being everywhere equidistant and not intersecting；词形变化：s:parallels/3:parallels/i:paralleling/p:parallelled/d:parallelled','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_49acbbf4a77b0b98e3',NULL,'paralyze','/''pærәlaiz/','vt. 使瘫痪, 使麻痹\n[医] 使麻痹, 使瘫痪；英英释义：v. make powerless and unable to function\nv. cause to be paralyzed and immobile；词形变化：d:paralyzed/3:paralyzes/i:paralyzing/p:paralyzed','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_392bd22533038ccf00',NULL,'parameter','/pә''ræmitә/','n. 参变数, 参变量, 参数, 参量\n[计] 参量; 参数；英英释义：n. a constant in the equation of a curve that can be varied to yield a family of similar curves\nn. any factor that defines a system and determines (or limits) its performance\nn. a quantity (such as the mean or variance) that characterizes a statistical population and that can be estimated by calculations from sample data；词形变化：s:parameters','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
