INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_0191cde7a66c5c00f3',NULL,'petition','/pi''tiʃәn/','n. 请愿, 诉状, 陈情书, 申请, 祈求, 祷文\nv. 正式请求, 恳求, 请愿；英英释义：v. write a petition for something to somebody; request formally and in writing；词形变化：s:petitions/p:petitioned/d:petitioned/i:petitioning/3:petitions','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
