INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_33fbb1a8291bb49966',NULL,'phase','/feiz/','n. 时期, 局面, 方面, 位相, 相, 阶段\nvt. 使调整相位, 使定相, 使一致, 逐步执行, 实行\n[计] 阶段；英英释义：n. any distinct time period in a sequence of events\nn. (physical chemistry) a distinct state of matter in a system; matter that is identical in chemical composition and physical state and separated from other material by the phase boundary\nn. a particular point in the time of a cycle; measured from some arbitrary zero and expressed as an angle\nn. (astronomy) the particular appearance of a body''s state of illumination (especially one of the recurring shapes of the part of Earth''s moon that is illuminated by the sun)；词形变化：s:phases/d:phased/i:phasing/p:phased/3:phases','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
