INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_06c176bddee6cc4c09',NULL,'philosopher','/fi''lɒsәfә/','n. 哲学家, 哲人, 思想开创人, 达观的人\n[法] 哲学家, 哲学研究者；英英释义：n. a specialist in philosophy\nn. a wise person who is calm and rational; someone who lives a life of reason with equanimity；词形变化：s:philosophers','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
