INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_a457ecf08f93186619',NULL,'physics','/''fiziks/','n. 物理学, 物理过程, 物理现象\n[化] 物理; 物理学；英英释义：n. the science of matter and energy and their interactions\nn. the physical properties, phenomena, and laws of something','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
