INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_43c11d847a429c9b74',NULL,'plea','/pli:/','n. 恳求, 辩解, 抗辩, 诉讼, 请愿, 托词\n[法] 抗辩, 申诉案件, 答辩；英英释义：n. (law) a defendant''s answer by a factual matter (as distinguished from a demurrer)\nn. an answer indicating why a suit should be dismissed；词形变化：s:pleas','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_452d3f29a13be6b459',NULL,'plead','/pli:d/','vi. 辩护, 恳求\nvt. 为...辩护, 提出...借口, 托称, 恳求；英英释义：v. appeal or request earnestly\nv. offer as an excuse or plea\nv. enter a plea, as in courts of law\nv. make an allegation in an action or other legal proceeding, especially answer the previous pleading of the other party by denying facts therein stated or by alleging new facts；词形变化：p:pleaded/i:pleading/d:pleaded/3:pleads','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
