INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_35a21124a8b1257a29',NULL,'plot','/plɒt/','n. 小块土地, 地区图, 图, 阴谋, 情节\nvt. 划分, 绘图, 密谋\nvi. 密谋, 策划\n[计] 绘制；英英释义：n. a secret scheme to do something (especially something underhand or illegal)\nn. a small area of ground covered by specific vegetation\nn. the story that is told in a novel or play or movie etc.\nn. a chart or map showing the movements or progress of an object；词形变化：s:plots/i:plotting/d:plotted/p:plotted/3:plots','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_eae118492a71cfaec2',NULL,'plough','/plau/','n. 犁, 犁过的地\nvi. 用犁耕田, 开路\nvt. 耕, 犁, 开路；英英释义：n a group of seven bright stars in the constellation Ursa Major\nn a farm tool having one or more heavy blades to break the soil and cut a furrow prior to sowing\nv move in a way resembling that of a plow cutting into or going through the soil\nv to break and turn over earth especially with a plow；词形变化：i:ploughing/p:ploughed/s:ploughs/d:ploughed/3:ploughs','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_f45cd2eb95796abfcc',NULL,'plug','/plʌg/','n. 塞子, 栓, 插头\nvt. 插入, 塞住, 接插头\nvi. 被塞住；英英释义：n. blockage consisting of an object designed to fill a hole tightly\nn. an electrical device with two or three pins that is inserted in a socket to make an electrical connection\nv. fill or close tightly with or as if with a plug\nv. persist in working hard；词形变化：d:plugged/s:plugs/i:plugging/3:plugs/p:plugged','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
