INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_8d4b4cd1eb51a83eee',NULL,'plunge','/plʌndʒ/','n. 钻进, 跳进, 跳水, 跳水池, 猛跌, 落下, 投入, 开始从事, 盲目投资\nvi. 投入, 投身于, 跳进, 陷入, 下降\nvt. 使投入, 使插入, 使陷入, 使遭受；英英释义：n. a steep and rapid fall\nv. dash violently or with great speed or impetuosity\nv. begin with vigor\nv. cause to be immersed；词形变化：p:plunged/d:plunged/i:plunging/3:plunges/s:plunges','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_f17bff869b292d91d6',NULL,'plural','/''pluәrәl/','n. 复数\na. 复数的, 两个以上的；英英释义：n. the form of a word that is used to denote more than one\na. composed of more than one member, set, or kind\na. grammatical number category referring to two or more items or units；词形变化：s:plurals','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
