INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_317529fb72260042fa',NULL,'poetry','/''pәuitri/','n. 诗, 韵文, 诗歌艺术；英英释义：n. literature in metrical form\nn. any communication resembling poetry in beauty or the evocation of feeling','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_27f016b46f30050d3e',NULL,'point','/pɒint/','n. 点, 小数点, 标点, 地点, 要点, 特点, 尖端, 分数, 得分, 穴位\nvt. 弄尖, 强调, 指出, 加标点于, 瞄准\nvi. 指, 指向, 表明；英英释义：n. a geometric element that has position but no extension\nn. the precise location of something; a spatially limited location\nn. a brief version of the essential meaning of something\nn. an instant of time；词形变化：s:points/p:pointed/i:pointing/3:points/d:pointed','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_7aa2a3bad66b8eb6da',NULL,'poison','/''pɒizn/','n. 毒药, 毒, 毒物, 有毒害的事物\nvt. 毒害, 毒杀, 使中毒\nvi. 放毒, 下毒；英英释义：n. any substance that causes injury or illness or death of a living organism\nn. anything that harms or destroys\nv. spoil as if by poison\nv. kill with poison；词形变化：s:poisons/d:poisoned/i:poisoning/p:poisoned/3:poisons','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_04ed22c3217203ab79',NULL,'poisonous','/''pɒizәnәs/','a. 有毒的, 恶毒的, 讨厌的\n[医] 有毒的；英英释义：s. having the qualities or effects of a poison\ns. not safe to eat\ns. marked by deep ill will; deliberately harmful','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_6b04f81a7f54067ca0',NULL,'poke','/pәuk/','n. 刺, 戳, 袋子\nvt. 戳, 捅, 拨弄, 刺\nvi. 戳, 刺, 捅, 搜索, 伸出, 行动散慢\n[计] 存数；英英释义：n. tall coarse perennial American herb having small white flowers followed by blackish-red berries on long drooping racemes; young fleshy stems are edible; berries and root are poisonous\nv. stir by poking\nv. make a hole by poking；词形变化：p:poked/i:poking/3:pokes/d:poked/s:pokes','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_6b45ca2f5a1e3e2d95',NULL,'polar','/''pәulә/','a. 两极的, 极地的, 正好相反的, 极性的\nn. 极线, 极面；英英释义：s. having a pair of equal and opposite charges\na. located at or near or coming from the earth''s poles\na. of or existing at or near a geographical pole or within the Arctic or Antarctic Circles；词形变化：s:polars','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_2f4d4ca00a3e6e85f0',NULL,'polarize','/''pәulәraiz/','v. (使)偏振, (使)极化, (使)两极分化；英英释义：v. cause to vibrate in a definite pattern\nv. cause to concentrate about two conflicting or contrasting positions\nv. become polarized in a conflict or contrasting situation；词形变化：d:polarized/i:polarizing/p:polarized/3:polarizes','','考研核心·学术','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_fd77117fc10517cf8f',NULL,'Pole','/pәul/','n. 波兰人, 极点, 磁极, 电极, 杆, 竿, 相反的极端\nvt. 用竿支撑\nvi. 撑篙；英英释义：n. a long (usually round) rod of wood or metal or plastic\nn. a native or inhabitant of Poland\nn. one of two divergent or mutually exclusive opinions\nn. one of two points of intersection of the Earth''s axis and the celestial sphere；词形变化：s:poles/i:poling/p:poled/d:poled/3:poles','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_92fd78b01890ed0650',NULL,'police','/pә''li:s/','n. 警察, 警察当局, 治安\nvt. 维持治安, 管辖；英英释义：n. the force of policemen and officers；词形变化：s:police/0:police/1:s/i:policing/d:policed/p:policed/3:polices','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_98563bc69283b0a9b0',NULL,'policy','/''pɒlisi/','n. 政策, 方针, 策略, 保险单\n[医] 凭单, 保险单；英英释义：n. a plan of action adopted by an individual or social group\nn. a line of argument rationalizing the course of action of a government\nn. written contract or certificate of insurance；词形变化：s:policies','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_b730b4c1e8da3032a0',NULL,'Polish','/''pɒliʃ/','a. 波兰的\nn. 波兰人, 上光剂, 光泽, 优雅\nvt. 擦亮, 擦去, 使完美\nvi. 擦亮, 变得光亮；英英释义：n. the property of being smooth and shiny\nn. a highly developed state of perfection; having a flawless or impeccable quality\nn. a preparation used in polishing\nn. the Slavic language of Poland；词形变化：d:polished/i:polishing/p:polished/s:polishes/3:polishes','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_5f795e655cb76e9492',NULL,'political','/pә''litikl/','a. 政治的, 政治上的, 政党的, 从事政治的\n[法] 政治的, 政治上的, 党派政治的；英英释义：a. involving or characteristic of politics or parties or politicians\na. of or relating to your views about social relationships involving authority or power\na. of or relating to the profession of governing','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
