INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_9d594743b06e505e35',NULL,'politics','/''pɒlitiks/','n. 政治, 政治学, 政见, 政治活动\n[法] 政治, 政治学, 政纲；英英释义：n. social relations involving intrigue to gain authority or power\nn. the study of government of states and other political units\nn. the profession devoted to governing and to political affairs\nn. the opinion you hold with respect to political questions','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
