INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_42ba5808564d6dadc7',NULL,'prick','/prik/','vt. 刺, 戳, 刺痛, 使竖起\nvi. 刺, 竖起\nn. 扎, 一刺, 刺痛\na. 竖起的；英英释义：n. the act of puncturing with a small point\nv. cause a stinging pain\nv. to cause a sharp emotional pain；词形变化：i:pricking/p:pricked/d:pricked/s:pricks/3:pricks','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_246e819a20fba7b3e4',NULL,'pride','/praid/','n. 骄傲, 自尊心, 自豪, 精华, 勇气\nvt. 以...自豪；英英释义：n. a feeling of self-respect and personal worth\nn. satisfaction with your (or another''s) achievements\nn. the trait of being spurred on by a dislike of falling below your standards\nn. a group of lions；词形变化：3:prides/p:prided/d:prided/s:prides/i:priding','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
