INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_d4b38c485d6445fea3',NULL,'primary','/''praimәri/','n. 最主要者, 原色\na. 主要的, 初期的, 根本的, 原始的, 首要的, 基本的\n[计] 初等量; 主要的; 一次的；英英释义：n. a preliminary election where delegates or nominees are chosen\nn. one of the main flight feathers projecting along the outer edge of a bird''s wing\nn. (astronomy) a celestial body (especially a star) relative to other objects in orbit around it\na. of first rank or importance or value; direct and immediate rather than secondary；词形变化：s:primaries','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_85f89ff793e50707b6',NULL,'prime','/praim/','n. 最佳部分, 初期, 全盛期\na. 主要的, 最初的, 根本的\nv. 加油启动, 灌注, 填装；英英释义：n. a number that has no factor but itself and 1\nn. the second canonical hour; about 6 a.m.\nn. the time of maturity when power and vigor are greatest\nv. insert a primer into (a gun, mine, or charge) preparatory to detonation or firing；词形变化：d:primed/i:priming/s:primes/p:primed/3:primes','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_32ee868714324a8c33',NULL,'primitive','/''primitiv/','n. 原始人, 早期艺术家\na. 原始的, 上古的\n[计] 图元; 原语; 基元；英英释义：n. a person who belongs to an early stage of civilization\nn. a mathematical expression from which another expression is derived\nn. a word serving as the basis for inflected or derived forms\ns. used of preliterate or tribal or nonindustrial societies；词形变化：s:primitives','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_5ba88abca0462c6493',NULL,'prince','/prins/','n. 王子, 亲王, 国君, 贵族, 诸侯, 有权势的大人物；英英释义：n. a male member of a royal family other than the sovereign (especially the son of a sovereign)；词形变化：s:princes','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
