INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_aba6f81c11f77388e7',NULL,'principal','/''prinsipәl/','n. 校长, 首长, 本金, 主犯, 资本, 委托人\na. 主要的, 最重要的, 首要的；英英释义：n. the original amount of a debt on which interest is calculated\nn. the educator who has executive authority for a school\nn. capital as contrasted with the income derived from it\nn. (criminal law) any person involved in a criminal offense, regardless of whether the person profits from such involvement；词形变化：s:principals','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_0ce89476c7e412ecf2',NULL,'principle','/''prinsipl/','n. 原则, 原理, 主义\n[化] 原理；英英释义：n. a basic generalization that is accepted as true and that can be used as a basis for reasoning or conduct\nn. a rule or standard especially of good behavior\nn. a basic truth or law or assumption\nn. a rule or law concerning a natural phenomenon or the function of a complex system；词形变化：s:principles','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_53350719cf4d2650d7',NULL,'print','/print/','n. 打印, 版, 印刷物, 痕迹, 印刷业, 印刷字体, 图片, 印花布, 印章\nv. 打印, 印刷, 铭记, 留印记于, 用印刷体写\n[计] DOS外部命令:在打印机上打印文件, 可一边打印文件一边执行其他工作；英英释义：n. the text appearing in a book, newspaper, or other printed publication\nn. a picture or design printed from an engraving\nn. availability in printed form\nn. a copy of a movie on film (especially a particular version of it)；词形变化：d:printed/s:prints/i:printing/p:printed/3:prints','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
