INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_b1babe91fa1b6c55c7',NULL,'private','/''praivit/','a. 私人的, 秘密的, 私立的, 隐蔽的\nn. 士兵, 隐士, 阴部\n[计] 私人的；英英释义：n. an enlisted man of the lowest rank in the Army or Marines\na. confined to particular persons or groups or providing privacy\ns. concerning things deeply private and personal；词形变化：s:privates','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_b4bdd2c7a729d26088',NULL,'privilege','/''privilidʒ/','n. 特权, 特别恩典, 基本权利, 特免\nvt. 给与...特权, 特免；英英释义：n. a special advantage or immunity or benefit not enjoyed by all\nn. (law) the right to refuse to divulge information obtained in a confidential relationship\nv. bestow a privilege upon；词形变化：s:privileges/i:privileging/d:privileged/p:privileged/3:privileges','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_fdd5d735e83cca0244',NULL,'prize','/praiz/','n. 奖赏, 奖金, 奖品, 战利品, 捕获\na. 得奖的\nvt. 珍视, 估价, 捕获, 撬, 撬动；英英释义：n. something given for victory or superiority in a contest or competition or for winning a lottery\nv. hold dear；词形变化：s:prizes/d:prized/p:prized/3:prizes/i:prizing','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_533baaa39dabf1e06b',NULL,'probability','/.prɒbә''biliti/','n. 可能性, 或然率, 几率, 概率\n[化] 概率; 几率；英英释义：n. a measure of how likely it is that some event will occur; a number expressing the ratio of favorable cases to the whole number of cases possible\nn. the quality of being probable; a probable event or the most probable event；词形变化：s:probabilities','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_60ab021a5b67619fe3',NULL,'probable','/''prɒbәbl/','a. 很可能的, 大概的, 可信的\nn. 很有希望的候选人, 很可能的事情；英英释义：n. an applicant likely to be chosen\na. likely but not certain to be or become true or real\ns. apparently destined；词形变化：s:probables','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_b8e507d904de2bd85a',NULL,'probe','/prәub/','n. 探索, 调查, 探针, 探测器\nv. 用探针探测, 调查, 探索；英英释义：n. an inquiry into unfamiliar or questionable activities\nn. a flexible slender surgical instrument with a blunt end that is used to explore wounds or body cavities\nn. an exploratory action or expedition\nn. an investigation conducted using a flexible surgical instrument to explore an injury or a body cavity；词形变化：s:probes/d:probed/i:probing/p:probed/3:probes','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_dd79c0a7aecb6decec',NULL,'procedure','/prә''si:dʒә/','n. 程序, 过程, 手续\n[计] 规程; 过程；英英释义：n. a particular course of action intended to achieve a result\nn. a mode of conducting legal and parliamentary proceedings；词形变化：s:procedures','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_0602fb6f9f83bccb18',NULL,'proceed','/prәu''si:d/','vi. 继续进行, 进行, 开始, 发出, 起诉\n[法] 所得, 收入, 收益；英英释义：v. move ahead; travel onward in time or space\nv. follow a certain course；词形变化：s:proceeds/p:proceeded/i:proceeding/3:proceeds/d:proceeded','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_7d099c9298b3184efa',NULL,'proceeding','/prәu''si:diŋ/','n. 进行, 程序, 行动, 诉讼程序, 事项\n[化] 会议论文集；英英释义：n. (law) the institution of a sequence of steps by which legal judgments are invoked；词形变化：0:proceed/1:i/s:proceedings/i:proceeding','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_ba33128c67b1251607',NULL,'process','/''prɒses/','n. 程序, 进行, 过程\nvt. 加工, 使...接受处理, 对...处置, 对...起诉\na. 经加工的, 有特殊光效的\n[计] 进程；英英释义：n. (psychology) the performance of some composite cognitive activity; an operation that affects mental contents\nn. a mental process that you are not directly aware of\nn. a natural prolongation or projection from a part of an organism either animal or plant\nn. a sustained phenomenon or one marked by gradual changes through a series of states；词形变化：s:processes/d:processed/i:processing/p:processed/3:processes','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_50170eb6d931d3b9eb',NULL,'procession','/prә''seʃәn/','n. 队伍, 连续, 列队行进, 涌出；英英释义：n. the group action of a collection of people or animals or vehicles moving ahead in more or less regular formation；词形变化：s:processions','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
