INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_0c9041d1904231bb50',NULL,'product','/''prɒdʌkt/','n. 产品, 结果, 乘积\n[化] 生产物；英英释义：n. an artifact that has been created by someone or some process\nn. a quantity obtained by multiplication\nn. a chemical substance formed as a result of a chemical reaction\nn. a consequence of someone''s efforts or of a particular set of circumstances；词形变化：s:products','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
