INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('01d310ef-2731-4e2a-80e8-21feecf9ec4f',NULL,'profound','/prә''faund/','a. 极深的, 深厚的, 深刻的, 渊博的；英英释义：a. showing intellectual penetration or emotional depth\ns. of the greatest intensity; complete\ns. coming from deep within one\ns. situated at or extending to great depth; too deep to have been sounded or plumbed；词形变化：t:profoundest/r:profounder','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_6dbe132f19d495673f',NULL,'programme','/''prәugræm/','n. 节目, 节目单, 程序, 纲要, 大纲, 计划\nvt. 规划, 拟...计划\nvi. 安排节目, 编程序；英英释义：n an announcement of the events that will occur as part of a theatrical or sporting event\nn an integrated course of academic studies\nn a radio or television show\nn (computer science) a sequence of instructions that a computer can interpret and execute\nn a system of projects or services intended to meet a public need\nn a series of steps to be carried out or goals to be accomplished\nn a performance (or series of performances) at a public presentation\nv write a computer program\nv arrange a program of or for；词形变化：s:programmes/d:programmed/p:programmed/i:programming/3:programs','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
