INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_82f677c54157ea48cd',NULL,'progressive','/prә''gresiv/','n. 改革论者, 进步论者\na. 前进的, 累进的, 进步的；英英释义：n. a tense of verbs used in describing action that is on-going\na. favoring or promoting progress\ns. favoring or promoting reform (often by government action)\na. (of taxes) adjusted so that the rate increases as the amount of income increases；词形变化：s:progressives','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
