INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_43a7a952c1807952f2',NULL,'proof','/pru:f/','n. 证据, 证明, 试验, 检验, 考验\na. 不能透入的, 证明用的, 防...的, 耐...的\nvt. 检验, 试验, 校对, 使不被穿透\n[计] 审稿；英英释义：n. any factual evidence that helps to establish the truth of something\nn. a formal series of statements showing that if one thing is true something else necessarily follows from it\nn. a measure of alcoholic strength expressed as an integer twice the percentage of alcohol present (by volume)\nn. (printing) an impression made to check for errors；词形变化：s:proofs/d:proofed/i:proofing/p:proofed/3:proofs','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_57ed06ac7da9880be2',NULL,'propaganda','/.prɒpә''gændә/','n. 宣传, 宣传活动\n[医] 宣传；英英释义：n. information that is spread for the purpose of promoting some cause','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('d4d51f50-cc60-45b1-9417-a01905450010',NULL,'propagate','/''prɒpәgeit/','vt. 繁殖, 传播, 传送\nvi. 繁殖, 蔓延；英英释义：v. transmit from one generation to the next\nv. travel through the air\nv. transmit\nv. transmit or cause to broaden or spread；词形变化：d:propagated/i:propagating/p:propagated/3:propagates','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_4c123f2647b9cc92d7',NULL,'propel','/prәu''pel/','vt. 推进, 驱使\n[机] 推进；英英释义：v. cause to move forward with force；词形变化：d:propelled/p:propelled/i:propelling/3:propels/s:propels','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_a439d881fe686759a3',NULL,'proper','/''prɒpә/','a. 适当的, 固有的, 高尚的, 专属的\nadv. 完全地, 彻底地；英英释义：a. marked by suitability or rightness or appropriateness\ns. having all the qualities typical of the thing specified; not just a snack"\ns. limited to the thing specified\ns. appropriate for a condition or purpose or occasion or a person''s character, needs','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_75e56351c0b2cd1248',NULL,'property','/''prɒpәti/','n. 财产, 所有权, 性质, 属性\n[计] 属性；英英释义：n. something owned; any tangible or intangible possession that is owned by someone; \nn. a basic or essential attribute shared by all members of a class\nn. a construct whereby objects or individuals can be distinguished\nn. any movable articles or objects used on the set of a play or movie；词形变化：s:properties','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_f46b2e86691b8b2cfe',NULL,'prophet','/''prɒfit/','n. 预言者, 先知, 提倡者；英英释义：n. an authoritative person who divines the future\nn. someone who speaks by divine inspiration; someone who is an interpreter of the will of God；词形变化：s:prophets','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_484fd821393fb9fcd0',NULL,'proportion','/prә''pɒ:ʃәn/','n. 比例, 比率, 均衡, 部分, 面积\nvt. 使成比例, 使均衡；英英释义：n. the quotient obtained when the magnitude of a part is divided by the magnitude of the whole\nn. magnitude or extent\nn. the relation between things (or parts of things) with respect to their comparative quantity, magnitude, or degree\nn. harmonious arrangement or relation of parts or elements within a whole (as in a design)；词形变化：s:proportions/d:proportioned/i:proportioning/p:proportioned/3:proportions','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_1b7c97adc09aeb02ee',NULL,'proposal','/prә''pәuzl/','n. 提议, 计划, 求婚\n[经] 提案, 申请, 投标；英英释义：n. something proposed (such as a plan or assumption)\nn. the act of making a proposal；词形变化：s:proposals','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_0c6de4914b0eaa403f',NULL,'propose','/prә''pәuz/','vt. 计划, 打算, 建议, 提议, 求(婚)\nvi. 打算, 求婚；英英释义：v. make a proposal, declare a plan for something\nv. ask (someone) to marry you；词形变化：d:proposed/p:proposed/i:proposing/3:proposes','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_f35d68bf300bd5e517',NULL,'proposition','/.prɒpә''ziʃәn/','n. 建议, 命题, 主张\nvt. 向...提议, 向...提出猥亵的要求；英英释义：n. (logic) a statement that affirms or denies something and is either true or false\nn. an offer for a private bargain (especially a request for sexual favors)\nn. a task to be dealt with\nv. suggest sex to；词形变化：s:propositions/d:propositioned/i:propositioning/p:propositioned/3:propositions','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('da1e9694-920d-4f79-952d-7d83597c5a36',NULL,'proprietary','/prә''praiәtәri/','a. 所有者的, 所有权的, 私有的\nn. 所有者, 业主, 所有权；英英释义：a. protected by trademark or patent or copyright; made or produced or distributed by one having exclusive rights','','考研核心·学术','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_41a6636045407cee3d',NULL,'prose','/prәuz/','n. 散文\nv. 写散文\na. 散文的, 平凡的；英英释义：n. ordinary writing as distinguished from verse\nn. matter of fact, commonplace, or dull expression；词形变化：s:proses/i:prosing','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_d5f3c7caa095960f48',NULL,'prosecute','/''prɒsikju:t/','vt. 告发, 起诉, 彻底进行, 执行, 从事\nvi. 告发, 起诉, 作检察官；英英释义：v. conduct a prosecution in a court of law\nv. bring a criminal action against (in a trial)\nv. carry out or participate in an activity; be involved in；词形变化：d:prosecuted/i:prosecuting/p:prosecuted/3:prosecutes','','考研核心·学术','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_86ba0bdefbb83162da',NULL,'prosecutor','/''prɒsikju:tә/','n. 实行者, 告发者, 公诉人\n[法] 原告, 起诉人, 检举人；英英释义：n. a government official who conducts criminal prosecutions on behalf of the state；词形变化：s:prosecutors','','考研核心·学术','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('027fd272-b08f-4572-838d-b9d592c101e3',NULL,'prospect','/''prɒspekt/','n. 景色, 展望\nvt. 勘探, 勘察\nvi. 勘探, 有前途；英英释义：n. the possibility of future success\nv. search for something desirable\nv. explore for useful or valuable things or substances, such as minerals；词形变化：s:prospects/i:prospecting/p:prospected/3:prospects/d:prospected','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_0de00ba763c45cdacc',NULL,'prospective','/prәs''pektiv/','a. 预期的, 将来的\n[经] 预期的, 未来的；英英释义：a. of or concerned with or related to the future；词形变化：s:prospectives','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_816dff0e1a963ddca1',NULL,'prosper','/''prɒspә/','vi. 繁荣, 兴隆, 成功\nvt. 使成功, 使昌盛；英英释义：v make steady progress; be at the high point in one''s career or reach a high point in historical significance or importance；词形变化：p:prospered/d:prospered/i:prospering/3:prospers','','考研核心·学术','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_ec05511370ee73d68d',NULL,'prosperity','/prɒs''periti/','n. 繁荣, 茂盛, 成功\n[经] 繁荣；英英释义：n. an economic state of growth with rising profits and full employment\nn. the condition of prospering; having good fortune；词形变化：s:prosperities','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_1da85cbdcee25b9469',NULL,'prosperous','/''prɒspәrәs/','a. 成功的, 繁盛的, 幸运的\n[经] 繁荣的, 昌盛的；英英释义：s in fortunate circumstances financially; moderately rich\ns very lively and profitable\ns marked by peace and prosperity\ns presaging or likely to bring good luck','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
